 {"id":"bd-14v4","title":"Implement FastApiTheme and theme presets","description":"# Implement Theme System

## Task Overview

Create the themes.rs module with the FastApiTheme struct containing all color definitions
for the fastapi_rust visual identity, plus theme presets for different preferences.

## Design Goals

1. **FastAPI Brand Identity**: Use colors inspired by FastAPI's documentation theme
2. **Semantic Colors**: Success, error, warning, info with clear visual meaning
3. **HTTP Method Colors**: Match Swagger UI conventions (familiar to API developers)
4. **Status Code Colors**: Quick visual identification of response categories
5. **Accessibility**: Sufficient contrast for readability
6. **Customization**: Allow users to define custom themes

## File: crates/fastapi-output/src/themes.rs

```rust
//! Theme system for fastapi_rust console output.
//!
//! Defines color palettes and styling presets for consistent
//! visual output across all components.

#[cfg(feature = "rich")]
use rich_rust::color::Color;

/// FastAPI-inspired color theme for console output.
///
/// All colors are stored as RGB tuples (r, g, b) for portability.
/// When used with rich_rust, these are converted to Color values.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct FastApiTheme {
    // === Brand Colors ===
    /// Primary brand color (teal, inspired by FastAPI docs)
    pub primary: (u8, u8, u8),
    /// Secondary brand color (green)
    pub secondary: (u8, u8, u8),
    /// Accent color for highlights (orange)
    pub accent: (u8, u8, u8),

    // === Semantic Colors ===
    /// Success indicator color (green)
    pub success: (u8, u8, u8),
    /// Warning indicator color (orange/yellow)
    pub warning: (u8, u8, u8),
    /// Error indicator color (red)
    pub error: (u8, u8, u8),
    /// Info indicator color (blue)
    pub info: (u8, u8, u8),

    // === HTTP Method Colors (Swagger UI conventions) ===
    /// GET method color (blue)
    pub http_get: (u8, u8, u8),
    /// POST method color (green)
    pub http_post: (u8, u8, u8),
    /// PUT method color (orange)
    pub http_put: (u8, u8, u8),
    /// DELETE method color (red)
    pub http_delete: (u8, u8, u8),
    /// PATCH method color (cyan)
    pub http_patch: (u8, u8, u8),
    /// OPTIONS method color (gray)
    pub http_options: (u8, u8, u8),
    /// HEAD method color (purple)
    pub http_head: (u8, u8, u8),

    // === Status Code Colors ===
    /// 1xx informational (gray)
    pub status_1xx: (u8, u8, u8),
    /// 2xx success (green)
    pub status_2xx: (u8, u8, u8),
    /// 3xx redirect (cyan)
    pub status_3xx: (u8, u8, u8),
    /// 4xx client error (yellow/orange)
    pub status_4xx: (u8, u8, u8),
    /// 5xx server error (red)
    pub status_5xx: (u8, u8, u8),

    // === Structural Colors ===
    /// Border color for boxes/panels
    pub border: (u8, u8, u8),
    /// Header text color
    pub header: (u8, u8, u8),
    /// Muted/secondary text color
    pub muted: (u8, u8, u8),
    /// Background highlight
    pub highlight_bg: (u8, u8, u8),
}

impl FastApiTheme {
    /// Create the default FastAPI-inspired theme.
    ///
    /// Colors chosen to match FastAPI documentation styling
    /// and Swagger UI conventions for familiarity.
    pub fn default() -> Self {
        Self {
            // Brand colors (FastAPI teal/green)
            primary: (0, 150, 136),      // #009688 - Teal 500
            secondary: (76, 175, 80),    // #4CAF50 - Green 500
            accent: (255, 152, 0),       // #FF9800 - Orange 500

            // Semantic colors
            success: (76, 175, 80),      // #4CAF50 - Green
            warning: (255, 152, 0),      // #FF9800 - Orange
            error: (244, 67, 54),        // #F44336 - Red
            info: (33, 150, 243),        // #2196F3 - Blue

            // HTTP methods (Swagger UI)
            http_get: (97, 175, 254),    // #61AFFE - Blue
            http_post: (73, 204, 144),   // #49CC90 - Green
            http_put: (252, 161, 48),    // #FCA130 - Orange
            http_delete: (249, 62, 62),  // #F93E3E - Red
            http_patch: (80, 227, 194),  // #50E3C2 - Cyan
            http_options: (128, 128, 128), // Gray
            http_head: (147, 112, 219),  // Purple

            // Status codes
            status_1xx: (128, 128, 128), // Gray
            status_2xx: (76, 175, 80),   // Green
            status_3xx: (0, 188, 212),   // Cyan
            status_4xx: (255, 193, 7),   // Yellow/Amber
            status_5xx: (244, 67, 54),   // Red

            // Structural
            border: (158, 158, 158),     // Gray 500
            header: (0, 150, 136),       // Primary
            muted: (117, 117, 117),      // Gray 600
            highlight_bg: (38, 50, 56),  // Blue Grey 900
        }
    }

    /// Create a neon/cyberpunk theme with high contrast.
    pub fn neon() -> Self {
        Self {
            primary: (0, 255, 255),      // Cyan
            secondary: (255, 0, 255),    // Magenta
            accent: (255, 255, 0),       // Yellow

            success: (0, 255, 128),      // Neon green
            warning: (255, 255, 0),      // Yellow
            error: (255, 0, 64),         // Hot pink/red
            info: (0, 128, 255),         // Electric blue

            http_get: (0, 255, 255),
            http_post: (0, 255, 128),
            http_put: (255, 165, 0),
            http_delete: (255, 0, 64),
            http_patch: (255, 0, 255),
            http_options: (128, 128, 128),
            http_head: (148, 0, 211),

            status_1xx: (128, 128, 128),
            status_2xx: (0, 255, 128),
            status_3xx: (0, 255, 255),
            status_4xx: (255, 255, 0),
            status_5xx: (255, 0, 64),

            border: (0, 255, 255),
            header: (255, 0, 255),
            muted: (100, 100, 100),
            highlight_bg: (20, 20, 40),
        }
    }

    /// Create a minimal grayscale theme with accent colors.
    pub fn minimal() -> Self {
        Self {
            primary: (200, 200, 200),
            secondary: (180, 180, 180),
            accent: (255, 152, 0),

            success: (100, 200, 100),
            warning: (255, 180, 0),
            error: (255, 100, 100),
            info: (100, 150, 255),

            http_get: (150, 150, 200),
            http_post: (150, 200, 150),
            http_put: (200, 180, 100),
            http_delete: (200, 100, 100),
            http_patch: (100, 200, 200),
            http_options: (128, 128, 128),
            http_head: (180, 150, 200),

            status_1xx: (128, 128, 128),
            status_2xx: (100, 200, 100),
            status_3xx: (100, 200, 200),
            status_4xx: (200, 180, 100),
            status_5xx: (200, 100, 100),

            border: (100, 100, 100),
            header: (220, 220, 220),
            muted: (80, 80, 80),
            highlight_bg: (30, 30, 30),
        }
    }

    /// Create a Monokai-inspired dark theme.
    pub fn monokai() -> Self {
        Self {
            primary: (166, 226, 46),     // Monokai green
            secondary: (102, 217, 239),  // Monokai cyan
            accent: (253, 151, 31),      // Monokai orange

            success: (166, 226, 46),
            warning: (253, 151, 31),
            error: (249, 38, 114),       // Monokai pink/red
            info: (102, 217, 239),

            http_get: (102, 217, 239),
            http_post: (166, 226, 46),
            http_put: (253, 151, 31),
            http_delete: (249, 38, 114),
            http_patch: (174, 129, 255), // Monokai purple
            http_options: (117, 113, 94),
            http_head: (174, 129, 255),

            status_1xx: (117, 113, 94),
            status_2xx: (166, 226, 46),
            status_3xx: (102, 217, 239),
            status_4xx: (253, 151, 31),
            status_5xx: (249, 38, 114),

            border: (117, 113, 94),
            header: (248, 248, 242),
            muted: (117, 113, 94),
            highlight_bg: (39, 40, 34),
        }
    }

    // === Color Conversion Helpers ===

    /// Get primary color as hex string.
    pub fn primary_hex(&self) -> String {
        rgb_to_hex(self.primary)
    }

    /// Get success color as hex string.
    pub fn success_hex(&self) -> String {
        rgb_to_hex(self.success)
    }

    /// Get error color as hex string.
    pub fn error_hex(&self) -> String {
        rgb_to_hex(self.error)
    }

    /// Get warning color as hex string.
    pub fn warning_hex(&self) -> String {
        rgb_to_hex(self.warning)
    }

    /// Get info color as hex string.
    pub fn info_hex(&self) -> String {
        rgb_to_hex(self.info)
    }

    /// Get accent color as hex string.
    pub fn accent_hex(&self) -> String {
        rgb_to_hex(self.accent)
    }

    /// Get color for HTTP method as hex string.
    pub fn http_method_hex(&self, method: &str) -> String {
        let color = match method.to_uppercase().as_str() {
            "GET" => self.http_get,
            "POST" => self.http_post,
            "PUT" => self.http_put,
            "DELETE" => self.http_delete,
            "PATCH" => self.http_patch,
            "OPTIONS" => self.http_options,
            "HEAD" => self.http_head,
            _ => self.muted,
        };
        rgb_to_hex(color)
    }

    /// Get color for status code as hex string.
    pub fn status_code_hex(&self, code: u16) -> String {
        let color = match code {
            100..=199 => self.status_1xx,
            200..=299 => self.status_2xx,
            300..=399 => self.status_3xx,
            400..=499 => self.status_4xx,
            500..=599 => self.status_5xx,
            _ => self.muted,
        };
        rgb_to_hex(color)
    }

    #[cfg(feature = "rich")]
    pub fn primary_color(&self) -> Color {
        Color::from_rgb(self.primary.0, self.primary.1, self.primary.2)
    }

    // ... similar methods for other colors
}

impl Default for FastApiTheme {
    fn default() -> Self {
        Self::default()
    }
}

/// Predefined theme presets.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Default)]
pub enum ThemePreset {
    /// Default FastAPI-inspired theme
    #[default]
    FastApi,
    /// Neon/cyberpunk high contrast theme
    Neon,
    /// Minimal grayscale with accents
    Minimal,
    /// Monokai dark theme
    Monokai,
}

impl ThemePreset {
    /// Get the FastApiTheme for this preset.
    pub fn theme(&self) -> FastApiTheme {
        match self {
            Self::FastApi => FastApiTheme::default(),
            Self::Neon => FastApiTheme::neon(),
            Self::Minimal => FastApiTheme::minimal(),
            Self::Monokai => FastApiTheme::monokai(),
        }
    }
}

impl std::str::FromStr for ThemePreset {
    type Err = ThemePresetParseError;

    fn from_str(s: &str) -> Result<Self, Self::Err> {
        match s.to_lowercase().as_str() {
            "fastapi" | "default" => Ok(Self::FastApi),
            "neon" | "cyberpunk" => Ok(Self::Neon),
            "minimal" | "gray" | "grey" => Ok(Self::Minimal),
            "monokai" | "dark" => Ok(Self::Monokai),
            _ => Err(ThemePresetParseError(s.to_string())),
        }
    }
}

/// Error parsing theme preset name.
#[derive(Debug, Clone)]
pub struct ThemePresetParseError(String);

impl std::fmt::Display for ThemePresetParseError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "unknown theme preset '{}', available: fastapi, neon, minimal, monokai", self.0)
    }
}

impl std::error::Error for ThemePresetParseError {}

/// Convert RGB tuple to hex string.
fn rgb_to_hex(rgb: (u8, u8, u8)) -> String {
    format!("#{:02x}{:02x}{:02x}", rgb.0, rgb.1, rgb.2)
}

/// Parse hex color to RGB tuple.
pub fn hex_to_rgb(hex: &str) -> Option<(u8, u8, u8)> {
    let hex = hex.trim_start_matches('#');
    if hex.len() == 6 {
        let r = u8::from_str_radix(&hex[0..2], 16).ok()?;
        let g = u8::from_str_radix(&hex[2..4], 16).ok()?;
        let b = u8::from_str_radix(&hex[4..6], 16).ok()?;
        Some((r, g, b))
    } else if hex.len() == 3 {
        let r = u8::from_str_radix(&hex[0..1], 16).ok()? * 17;
        let g = u8::from_str_radix(&hex[1..2], 16).ok()? * 17;
        let b = u8::from_str_radix(&hex[2..3], 16).ok()? * 17;
        Some((r, g, b))
    } else {
        None
    }
}
```

