impl TestResultsDisplay {
    pub fn display(&self) {
        let output = RichOutput::global();

        if !output.should_render() {
            self.display_plain(&output);
            return;
        }

        let theme = output.theme();
        let mut content = Vec::new();

        for suite in &self.suites {
            if self.group_by_module {
                content.push(theme.style_text(&suite.name, "bold"));
            }

            for result in &suite.results {
                if !self.show_passed && matches!(result.status, TestStatus::Passed) {
                    continue;
                }

                let (icon, style) = match result.status {
                    TestStatus::Passed => ("✓", "green"),
                    TestStatus::Failed => ("✗", "red bold"),
                    TestStatus::Skipped => ("⊘", "yellow"),
                    TestStatus::Ignored => ("◌", "dim"),
                };

                let timing = if self.show_timing {
                    format!(" {:>4}ms", result.duration.as_millis())
                } else {
                    String::new()
                };

                let dots = ".".repeat(50 - result.name.len().min(48));

                content.push(format!(
                    "  {} {} {}{}",
                    theme.style_text(icon, style),
                    result.name,
                    dots,
                    timing
                ));

                // Show failure details
                if let Some(msg) = &result.failure_message {
                    content.push(theme.style_text(&format!("    │ {}", msg), "red"));
                }

                if let Some((expected, actual)) = &result.failure_diff {
                    content.push(theme.style_text(
                        &format!("    │ Expected: {}", expected), "green dim"
                    ));
                    content.push(theme.style_text(
                        &format!("    │ Actual:   {}", actual), "red dim"
                    ));
                }
            }
            content.push(String::new());
        }

        // Summary section
        let stats = self.calculate_stats();

        content.push("─".repeat(50));
        content.push(theme.style_text("Summary", "bold"));

        // Progress bar
        let pass_ratio = stats.passed as f64 / stats.total as f64;
        let bar = self.render_progress_bar(pass_ratio, 30);
        content.push(format!(
            "{} {}% ({}/{})",
            bar,
            (pass_ratio * 100.0) as u32,
            stats.passed,
            stats.total
        ));

        content.push(String::new());
        content.push(format!(
            "✓ Passed:  {:3}    Duration: {:.2}s",
            stats.passed,
            stats.total_duration.as_secs_f64()
        ));
        content.push(format!(
            "✗ Failed:  {:3}    Slowest:  {} {}ms",
            stats.failed,
            stats.slowest_test,
            stats.slowest_duration.as_millis()
        ));
        content.push(format!("⊘ Skipped: {:3}", stats.skipped));

        let panel = Panel::from_text(&content.join("\n"))
            .title("Test Results")
            .rounded();

        output.renderable(&panel);
    }

    fn render_progress_bar(&self, ratio: f64, width: usize) -> String {
        let filled = (ratio * width as f64) as usize;
        let empty = width - filled;
        format!("{}{}" , "█".repeat(filled), "░".repeat(empty))
    }
}
